// frontend/src/FlowCanvas.jsx
import React from "react";
import ReactFlow, { Background, Controls, MiniMap, useReactFlow } from "reactflow";
import "reactflow/dist/style.css";
import { nodeTypes } from "./nodes/registryNode";
import { submitPipeline } from "./submit";

export default function FlowCanvas({
  nodes,
  edges,
  onNodesChange,
  onEdgesChange,
  onConnect,
  setNodes, // <-- make sure App passes setNodes down
}) {
  const { project } = useReactFlow();

  const handleSubmit = () => {
    submitPipeline(nodes, edges);
  };

  const onDragOver = (event) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = "move";
  };

  const onDrop = (event) => {
    event.preventDefault();
    const reactFlowBounds = event.currentTarget.getBoundingClientRect();
    const data = JSON.parse(event.dataTransfer.getData("application/reactflow"));

    const position = project({
      x: event.clientX - reactFlowBounds.left,
      y: event.clientY - reactFlowBounds.top,
    });

    const newNode = {
      id: `${data.nodeType}-${Date.now()}`,
      type: data.nodeType,
      position,
      data: data.data || { label: data.nodeType },
      className: data.className, // will be "delete-node" for DeleteNode
    };

    setNodes((nds) => nds.concat(newNode));
  };

  return (
    <div style={{ width: "100%", height: "100vh", position: "relative" }}>
      <ReactFlow
        nodes={nodes}
        edges={edges}
        nodeTypes={nodeTypes}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        onDrop={onDrop}
        onDragOver={onDragOver}
        fitView
      >
        <Background />
        <Controls />
        <MiniMap />
      </ReactFlow>

      {/* Submit button overlay */}
      <button
        onClick={handleSubmit}
        style={{
          position: "absolute",
          top: 20,
          right: 20,
          zIndex: 10,
          padding: "8px 16px",
          backgroundColor: "#4f46e5",
          color: "#fff",
          border: "none",
          borderRadius: "6px",
          cursor: "pointer",
          fontWeight: "600",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
        }}
      >
        Submit Pipeline
      </button>
    </div>
  );
}
